module nearest_neighbor_interpolation(
    input [7:0] pixel,     // Current pixel value
    input [7:0] up,        // Upper neighbor pixel value
    input [7:0] down,      // Lower neighbor pixel value
    input [7:0] left,      // Left neighbor pixel value
    input [7:0] right,     // Right neighbor pixel value
    output reg [7:0] interpolated_pixel   // Interpolated pixel value
);

    always @(*) begin
        if (pixel != 8'b0) begin
            interpolated_pixel = pixel; // If the current pixel is not zero, retain its value.
        end else begin
            // Check neighboring pixels
            if (up != 8'b0) interpolated_pixel = up;
            else if (down != 8'b0) interpolated_pixel = down;
            else if (left != 8'b0) interpolated_pixel = left;
            else if (right != 8'b0) interpolated_pixel = right;
            else interpolated_pixel = 8'b0; // If all neighbors are zero, output zero.
        end
    end
endmodule
